struct Session {
    std::string data;
    std::chrono::system_clock::time_point expiryTime;

    Session(const std::string& sessionData, int ttlSeconds)
        : data(sessionData),
          expiryTime(std::chrono::system_clock::now() + std::chrono::seconds(ttlSeconds)) {}
};

class SessionCache {
private:
    std::unordered_map<std::string, std::shared_ptr<Session>> cache;

public:
    void createSession(const std::string& sessionId, const std::string& sessionData, int ttlSeconds) {
        auto session = std::make_shared<Session>(sessionData, ttlSeconds);
        cache[sessionId] = session;
    }

    std::optional<std::string> accessSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it == cache.end()) {
            return std::nullopt; // Session not found
        }

        auto& session = it->second;
        if (std::chrono::system_clock::now() > session->expiryTime) {
            cache.erase(it); // Session expired, remove from cache
            return std::nullopt;
        }

        return session->data;
    }

    void invalidateSession(const std::string& sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            cache.erase(it); // Invalidate session by removing it from cache
        }
    }
};

